import React, { useEffect, useRef, useState } from 'react';
import API from '../../api/axios';
import MessageBubble from './MessageBubble';
import TypingIndicator from './TypingIndicator';

export default function ChatBox({ chat, socketRef }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);

  // Call States
  const [incomingCall, setIncomingCall] = useState(null);
  const [callActive, setCallActive] = useState(false);
  const [isAudioOnly, setIsAudioOnly] = useState(false);

  // WebRTC Refs
  const localVideo = useRef(null);
  const remoteVideo = useRef(null);
  const peerRef = useRef(null);
  const localStreamRef = useRef(null);
  const pendingCandidates = useRef([]); 

  const scrollRef = useRef();

  const getMe = () => JSON.parse(localStorage.getItem('user') || 'null');

  const getPartnerId = () => {
    const me = getMe();
    if (!chat || !chat.users) return null;
    const partner = chat.users.find(u => {
      const id = typeof u === 'string' ? u : (u._id || u.id);
      return String(id) !== String(me?._id);
    });
    return typeof partner === 'string' ? partner : (partner?._id || partner?.id);
  };

  // --- WebRTC Logic ---

  const createPeer = (targetId) => {
    const pc = new RTCPeerConnection({
      iceServers: [
        { urls: "stun:stun.l.google.com:19302" },
        { urls: "stun:stun1.l.google.com:19302" }
      ]
    });

    pc.onicecandidate = (event) => {
      if (event.candidate && socketRef.current) {
        socketRef.current.emit("ice_candidate", {
          to: targetId,
          candidate: event.candidate
        });
      }
    };

    pc.ontrack = (event) => {
      console.log("Remote track received:", event.streams[0]);
      if (remoteVideo.current) {
        remoteVideo.current.srcObject = event.streams[0];
      }
    };

    pc.onconnectionstatechange = () => {
      if (pc.connectionState === "failed" || pc.connectionState === "disconnected") {
        endCall();
      }
    };

    return pc;
  };

  const startCall = async (audioOnly = false) => {
    try {
      const partnerId = getPartnerId();
      if (!partnerId) return;

      setIsAudioOnly(audioOnly);

      // 1. Get Media First
      const stream = await navigator.mediaDevices.getUserMedia({
        video: !audioOnly,
        audio: true
      });
      localStreamRef.current = stream;

      // 2. Set UI Local Video
      if (localVideo.current) localVideo.current.srcObject = stream;

      // 3. Create Connection and ADD TRACKS BEFORE OFFER
      const pc = createPeer(partnerId);
      stream.getTracks().forEach(track => pc.addTrack(track, stream));

      // 4. Create Offer
      const offer = await pc.createOffer();
      await pc.setLocalDescription(offer);

      socketRef.current.emit("call_user", {
        to: partnerId,
        offer,
        from: getMe()?._id,
        isAudioOnly: audioOnly
      });

      peerRef.current = pc;
      setCallActive(true);
    } catch (err) {
      console.error("Failed to start call:", err);
    }
  };

  const acceptCall = async () => {
    try {
      const { offer, from, isAudioOnly: incomingAudio } = incomingCall;
      setIsAudioOnly(incomingAudio);

      // 1. Get Media First
      const stream = await navigator.mediaDevices.getUserMedia({
        video: !incomingAudio,
        audio: true
      });
      localStreamRef.current = stream;
      if (localVideo.current) localVideo.current.srcObject = stream;

      // 2. Create Connection and ADD TRACKS BEFORE ANSWER
      const pc = createPeer(from);
      stream.getTracks().forEach(track => pc.addTrack(track, stream));

      // 3. Set Remote Offer
      await pc.setRemoteDescription(new RTCSessionDescription(offer));

      // 4. Handle early candidates
      while (pendingCandidates.current.length > 0) {
        const candidate = pendingCandidates.current.shift();
        await pc.addIceCandidate(new RTCIceCandidate(candidate));
      }

      // 5. Create Answer
      const answer = await pc.createAnswer();
      await pc.setLocalDescription(answer);

      socketRef.current.emit("answer_call", { to: from, answer });

      peerRef.current = pc;
      setIncomingCall(null);
      setCallActive(true);
    } catch (err) {
      console.error("Failed to accept call:", err);
    }
  };

  const endCall = () => {
    const partnerId = getPartnerId();
    if (socketRef.current && partnerId) {
      socketRef.current.emit("end_call", { to: partnerId });
    }
    cleanupCall();
  };

  const cleanupCall = () => {
    if (peerRef.current) {
      peerRef.current.close();
      peerRef.current = null;
    }
    if (localStreamRef.current) {
      localStreamRef.current.getTracks().forEach(t => t.stop());
      localStreamRef.current = null;
    }
    pendingCandidates.current = [];
    setCallActive(false);
    setIncomingCall(null);
  };

  // --- Effects ---

  useEffect(() => {
    const socket = socketRef?.current;
    if (!socket) return;

    socket.on('incoming_call', (data) => setIncomingCall(data));

    socket.on('call_answered', async ({ answer }) => {
      if (peerRef.current) {
        try {
          await peerRef.current.setRemoteDescription(new RTCSessionDescription(answer));
          while (pendingCandidates.current.length > 0) {
            const candidate = pendingCandidates.current.shift();
            await peerRef.current.addIceCandidate(new RTCIceCandidate(candidate));
          }
        } catch (e) { console.error("Error setting answer:", e); }
      }
    });

    socket.on('ice_candidate', async ({ candidate }) => {
      if (peerRef.current?.remoteDescription) {
        try {
          await peerRef.current.addIceCandidate(new RTCIceCandidate(candidate));
        } catch (e) { console.error("Error adding candidate:", e); }
      } else {
        pendingCandidates.current.push(candidate);
      }
    });

    socket.on('call_ended', () => cleanupCall());

    return () => {
      socket.off('incoming_call');
      socket.off('call_answered');
      socket.off('ice_candidate');
      socket.off('call_ended');
    };
  }, [socketRef]);

  // Standard Chat Effects
  useEffect(() => {
    if (!chat) return;
    const loadMessages = async () => {
      try {
        const res = await API.get(`/messages/${chat._id}`);
        setMessages(res.data);
        scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
      } catch (e) {}
    };
    loadMessages();
    socketRef.current?.emit('join_chat', chat._id);
  }, [chat, socketRef]);

  const sendMessage = async () => {
    if (!input.trim() || !chat) return;
    try {
      const res = await API.post('/messages', { content: input, chat: chat._id });
      setMessages(p => [...p, res.data]);
      socketRef.current?.emit('new_message', res.data);
      setInput('');
    } catch (e) {}
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100vh', background: '#fff' }}>
      <div style={{ padding: '15px', borderBottom: '1px solid #ddd', display: 'flex', justifyContent: 'space-between' }}>
        <strong>{chat?.chatName || "Chat"}</strong>
        {!callActive && (
          <div>
            <button onClick={() => startCall(false)} style={btnStyle}>📹 Video</button>
            <button onClick={() => startCall(true)} style={{...btnStyle, marginLeft: 5}}>🎧 Audio</button>
          </div>
        )}
      </div>

      <div style={{ flex: 1, overflowY: 'auto', padding: '15px', background: '#f5f5f5' }}>
        {messages.map(m => <MessageBubble key={m._id} m={m} />)}
        <div ref={scrollRef} />
      </div>

      {incomingCall && !callActive && (
        <div style={overlayStyle}>
          <p>Incoming Call...</p>
          <button onClick={acceptCall} style={{...btnStyle, background: 'green'}}>Accept</button>
          <button onClick={() => setIncomingCall(null)} style={{...btnStyle, background: 'red', marginLeft: 10}}>Decline</button>
        </div>
      )}

      {callActive && (
        <div style={videoContainerStyle}>
          <video ref={remoteVideo} autoPlay playsInline style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
          {!isAudioOnly && (
            <video ref={localVideo} autoPlay muted playsInline style={miniVideoStyle} />
          )}
          <button onClick={endCall} style={hangupStyle}>End Call</button>
        </div>
      )}

      <div style={{ padding: '10px', display: 'flex', gap: 10 }}>
        <input 
          value={input} 
          onChange={e => setInput(e.target.value)}
          placeholder="Message..." 
          style={{ flex: 1, padding: 10, borderRadius: 20, border: '1px solid #ccc' }}
        />
        <button onClick={sendMessage} style={btnStyle}>Send</button>
      </div>
    </div>
  );
}

const btnStyle = { background: '#0084ff', color: '#fff', border: 'none', padding: '8px 15px', borderRadius: '5px', cursor: 'pointer' };
const overlayStyle = { position: 'fixed', top: '20%', left: '50%', transform: 'translate(-50%, -50%)', background: '#fff', padding: 20, zIndex: 1000, borderRadius: 10, boxShadow: '0 4px 10px rgba(0,0,0,0.2)' };
const videoContainerStyle = { position: 'relative', height: '400px', background: '#000' };
const miniVideoStyle = { position: 'absolute', bottom: 10, right: 10, width: 120, border: '2px solid white', borderRadius: 8 };
const hangupStyle = { position: 'absolute', bottom: 20, left: '50%', transform: 'translateX(-50%)', background: 'red', color: 'white', border: 'none', padding: '10px 20px', borderRadius: 30 };
